import { Injectable } from '@nestjs/common';
import { EventBus } from '../events/event-bus';
import { EmailService } from './email.service';
import { UserRepository } from '../repositories/user.repository';
import { OrderRepository } from '../repositories/order.repository';
import { Logger } from '../utils/logger';

@Injectable()
export class NotificationService {
  private readonly logger = new Logger(NotificationService.name);

  constructor(
    private readonly eventBus: EventBus,
    private readonly emailService: EmailService,
    private readonly userRepo: UserRepository,
    private readonly orderRepo: OrderRepository,
  ) {}

  onModuleInit(): void {
    this.registerListeners();
  }

  private registerListeners(): void {
    this.eventBus.on('user.registered', (payload) => {
      this.handleUserRegistered(payload);
    });

    this.eventBus.on('order.completed', async (payload) => {
      await this.handleOrderCompleted(payload);
    });
  }

  private async handleUserRegistered(payload: { userId: string }): Promise<void> {
    const user = await this.userRepo.findById(payload.userId);
    if (!user) return;
    await this.emailService.sendWelcomeEmail(user.email, user.name);
  }

  private async handleOrderCompleted(payload: { orderId: string; userId: string }): Promise<void> {
    const [user, order] = await Promise.all([
      this.userRepo.findById(payload.userId),
      this.orderRepo.findById(payload.orderId),
    ]);

    if (!user || !order) {
      this.logger.warn('Missing user or order for completed notification', {
        orderId: payload.orderId,
        userId: payload.userId,
      });
      return;
    }

    await this.emailService.sendOrderConfirmation(user.email, {
      orderNumber: order.orderNumber,
      total: order.total,
      items: order.items,
      estimatedDelivery: order.estimatedDelivery,
    });

    this.logger.log('Order completion email sent', { orderId: order.id, userId: user.id });
  }
}

