### src/middleware/auth.middleware.ts (symbol: session)
**Rationale:** Auth middleware looks up sessions with underscore-separated keys (session_userId_token) but the new service stores them with colon-separated keys (session:userId:token). Sessions will never validate.
```
import { Injectable, NestMiddleware, UnauthorizedException, Inject } from '@nestjs/common';
import { Request, Response, NextFunction } from 'express';
import { RedisClient } from '../infrastructure/redis.client';

@Injectable()
export class AuthMiddleware implements NestMiddleware {
  constructor(
    @Inject('REDIS_CLIENT') private readonly redis: RedisClient,
  ) {}

  async use(req: Request, _res: Response, next: NextFunction): Promise<void> {
    const token = this.extractBearerToken(req);
    const userId = req.headers['x-user-id'] as string;

    if (!token || !userId) {
      throw new UnauthorizedException('Missing credentials');
    }

    // Session lookup uses underscore-separated key format
    const sessionKey = `session_${userId}_${token}`;
    const sessionRaw = await this.redis.get(sessionKey);

    if (!sessionRaw) {
      throw new UnauthorizedException('Invalid or expired session');
    }

    const session = JSON.parse(sessionRaw);
    if (session.expiresAt < Date.now()) {
      await this.redis.del(sessionKey);
      throw new UnauthorizedException('Session expired');
    }

    req['session'] = session;
    next();
  }
}
